import requests
from flask import Flask, jsonify

app = Flask(__name__)

@app.route("/weather")
def weather():
    '''
    Fetch the latest weather forecast for St. John's from a trusted API,
    parse the JSON response, and return it in a friendly format.
    Sure, 'tis handier than askin' the old-timers, b'y!
    '''
    try:
        response = requests.get("https://api.weather.gc.ca/forecast?city=StJohns")
        response.raise_for_status()
        forecast = response.json()
        return jsonify({
            "message": "Here's the weather for ye, me love!",
            "forecast": forecast
        })
    except Exception as e:
        return jsonify({
            "message": "Couldn't fetch the weather, b'y. Try again later, sure.",
            "error": str(e)
        })

