@app.route('/fetch_recipe', methods=['GET'])
def fetch_recipe():
    """
    Get 'dish' from the query args, and look up a traditional Newfoundland recipe.
    Return a friendly response with cooking tips and a bit o' local lore.
    """
    dish_name = request.args.get('dish', '').strip()
    if not dish_name:
        return "Ah, b’y, ye forgot to tell me what dish ye’re after!"

    recipes = {
        'jiggs dinner': "Boil salt beef, add cabbage, turnip, carrot, and potato. Don’t forget the pease pudding! Serve with mustard pickles.",
        'fish and brewis': "Soak hardtack overnight, fry with salt cod and scrunchions. A true taste o’ the sea!",
        'toutons': "Fried bread dough, best served with molasses or corn syrup. A fine breakfast, me son!"
    }

    recipe = recipes.get(dish_name.lower(), "Sorry, me duck, I don’t know that one. Try askin’ for jiggs dinner or fish and brewis!")
    return f"Here’s how ye makes it: {recipe} Mind ye, every kitchen’s got its own twist!"

