from flask import Flask, jsonify
app = Flask(__name__)


def calculate_fish_weight(length, girth):
    """Calculate the weight of a fish in pounds, b'y."""
    return (length * girth * girth) / 800


@app.route('/fish_weight', methods=['GET'])
def fish_weight_calc():
    '''
    Takes in length and girth of a fish from query params,
    calculates the weight, then gives back the result.
    '''
    try:
        length = float(request.args.get('length', 0))
        girth = float(request.args.get('girth', 0))
        weight = calculate_fish_weight(length, girth)
        return jsonify({'weight': f"Dat fish weighs bout {weight:.1f} pounds, me son!"})
    except Exception as e:
        return jsonify({'note': "Oops! Couldn't calculate dat, b'y. Try again!"})

