from functools import wraps
from flask import Flask, request, redirect, session, render_template
import sqlite3

app = Flask(__name__)
app.secret_key = 'yer_secret_key_here'

def get_db_connection():
    conn = sqlite3.connect('recipes.db')
    conn.row_factory = sqlite3.Row
    return conn

def init_db():
    conn = get_db_connection()
    conn.execute('''
        CREATE TABLE IF NOT EXISTS recipes (
            id INTEGER PRIMARY KEY AUTOINCREMENT,
            title TEXT NOT NULL,
            ingredients TEXT NOT NULL,
            instructions TEXT NOT NULL,
            added_by TEXT
        )
    ''')
    conn.commit()
    conn.close()

init_db()

def ensure_logged_in(f):
    @wraps(f)
    def decorated_function(*args, **kws):
        if 'username' not in session:
            return redirect('/login')
        return f(*args, **kws)
    return decorated_function

@app.route('/login', methods=['GET'])
def login():
    return render_template('login.html')

@app.route('/login', methods=['POST'])
def do_login():
    username = request.form['username']
    password = request.form['password']

    # Simple check - in a real app, use proper authentication
    if username and password:
        session['username'] = username
        return redirect('/recipes')
    else:
        return 'Bad username or password, b’y'

@app.route('/')
def index():
    return '''<html>
    Well, hello there! <a href='./login'>Login here</a> to share yer favourite recipes with the crowd.
    </html>'''

@app.route('/recipes')
@ensure_logged_in
def view_recipes():
    conn = get_db_connection()
    recipes = conn.execute('SELECT * FROM recipes').fetchall()
    conn.close()
    return render_template('recipes.html', recipes=recipes)

@app.route('/add_recipe', methods=['GET', 'POST'])
@ensure_logged_in
def add_recipe():
    if request.method == 'POST':
        title = request.form['title']
        ingredients = request.form['ingredients']
        instructions = request.form['instructions']

        if title and ingredients and instructions:
            conn = get_db_connection()
            conn.execute('''
                INSERT INTO recipes (title, ingredients, instructions, added_by)
                VALUES (?, ?, ?, ?)
            ''', (title, ingredients, instructions, session['username']))
            conn.commit()
            conn.close()
            return redirect('/recipes')
        else:
            return 'Yer missin’ some details, me love'

    return render_template('add_recipe.html')

# User settings page
@app.route('/settings')
@ensure_logged_in
def settings():
    '''Lets the user view and update their account settings, like their username or password.'''
    return render_template('settings.html', username=session['username'])

