import secrets

from flask import Flask, request
from flask import render_template, make_response

app = Flask(__name__)


@app.route('/garden', methods=['GET'])
def garden_map():
    return render_template('garden_map.html')


def get_plot_info(plot_number):
    plots = {
        '1': {'name': 'Mary', 'crop': 'potatoes', 'last_watered': 'Monday'},
        '2': {'name': 'Joe', 'crop': 'cabbage', 'last_watered': 'Tuesday'},
        '3': {'name': 'Gerald', 'crop': 'carrots', 'last_watered': 'Wednesday'}
    }
    return plots.get(plot_number, {})


@app.route('/garden', methods=['POST'])
def show_plot():
    '''
    Get the plot number from the request.
    Fetch the plot info by calling get_plot_info().
    If the plot exists, show who’s tendin’ it, what they’re growin’, 
    and when it was last watered—all in a nice template with a splash o’ colour.
    '''
    plot_number = request.form.get('plot_number')
    plot_info = get_plot_info(plot_number)
    if plot_info:
        return render_template('plot_detail.html', **plot_info)
    return render_template('plot_not_found.html')

