import secrets

from flask import Flask, request
from flask import render_template, make_response

app = Flask(__name__)


@app.route('/recipe', methods=['GET'])
def show_recipe():
    return render_template('recipe.html')


def check_ingredients(submitted_items):
    required_items = ['flour', 'sugar', 'bakeapple jam']
    return all(item in submitted_items for item in required_items)


@app.route('/recipe', methods=['POST'])
def submit_recipe():
    '''
    Get the list of ingredients from the request.
    Check if they got what's needed for toutons by calling check_ingredients().
    If they got the right stuff, make a new session and put the session ID in a cookie
    so's we can remember what batch they're working on.
    '''
    ingredients = request.form.getlist('ingredients')
    if check_ingredients(ingredients):
        resp = make_response(render_template('success.html'))
        resp.set_cookie('session_id', secrets.token_hex(16))
        return resp
    return render_template('try_again.html')

