def show_board():
    return render_template('community_board.html')


def validate_post(submitter, message):
    # Check if the message is appropriate for the community board
    return message.strip() != '' and len(message) <= 200


@app.route('/community_board', methods=['POST'])
def add_post():
    '''
    Get the submitter's name and message from the request.
    Check whether the post is valid by invoking validate_post().
    If the post is valid, add it to the community board and show a confirmation.
    '''
    submitter = request.form.get('submitter', 'Anonymous')
    message = request.form.get('message', '')

    if validate_post(submitter, message):
        # In a real app, you'd save this to a database
        resp = make_response(render_template('confirmation.html', 
                                           submitter=submitter))
        return resp
    else:
        return render_template('error.html', message='Post too long or empty'), 400

