import kitchen_lib

PANTRY_DB = kitchen_lib.connect('local_kitchen', config=config)


def findRecipe(recipe_name, cook_type):
    '''
    Fetch the touton recipe from the kitchen book by its name and how ye wants it cooked.
    '''
    response = PANTRY_DB.query(
        TableName='kitchen_book',
        KeyConditionExpression='recipe_name = :name AND cook_type = :type',
        ExpressionAttributeValues={
            ':name': {'S': recipe_name},
            ':type': {'S': cook_type}
        }
    )
    return response.get('Items', [])
